#include <bits/stdc++.h>
using namespace std;
struct Node{
    int k,id;
};
bool b[1000];
int n;
string s;
stack<Node> p;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    cin>>s;
    n=s.size(),s=" "+s;
    for(int i=1;i<=n;i++){
        if(s[i]=='(')
            p.push({1,i});
        else if(s[i]=='[')
            p.push({2,i});
        else if(s[i]==')'){
            if(p.size() && p.top().k==1)
                p.pop();
            else
                b[i]=1;
        }else{
            if(p.size() && p.top().k==2)
                p.pop();
            else
                b[i]=1;
        }
    }
    while(p.size()){
        b[p.top().id]=1;
        p.pop();
    }
    for(int i=1;i<=n;i++){
        if(b[i]){
            if(s[i]==')')
                cout<<'(';
            if(s[i]==']')
                cout<<'[';
        }
        cout<<s[i];
        if(b[i]){
            if(s[i]=='(')
                cout<<')';
            if(s[i]=='[')
                cout<<']';
        }
    }
    return 0;
}
